1	import { quote, claim, type Item } from "./claim-office.js";
2	
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type ClaimStep = {
5	  op: "claim";
6	  policy: number;
7	  incident: { damages: { itemType: string; amount: number }[] };
8	};
9	type Step = QuoteStep | ClaimStep;
10	
11	const chunks: Buffer[] = [];
12	process.stdin.on("data", (c) => chunks.push(c));
13	process.stdin.on("end", () => {
14	  const input = JSON.parse(Buffer.concat(chunks).toString("utf-8"));
15	  const customer = input.customer;
16	  const policies: Record<number, { items: Item[]; remainingCap: number | undefined }> = {};
17	  const results: unknown[] = [];
18	  (input.steps as Step[]).forEach((step, i) => {
19	    if (step.op === "quote") {
20	      policies[i] = { items: step.items, remainingCap: undefined };
21	      results.push({ premium: quote({ items: step.items, customer }) });
22	    } else {
23	      const policy = policies[step.policy];
24	      const out = claim({
25	        items: policy.items,
26	        damages: step.incident.damages,
27	        remainingCap: policy.remainingCap,
28	      });
29	      policy.remainingCap = out.remainingCap;
30	      results.push({ payout: out.payout, remainingCap: out.remainingCap });
31	    }
32	  });
33	  process.stdout.write(JSON.stringify({ results }));
34	});
